query:
-- Validation 1: sentVia distribution
SELECT sent_via, COUNT(*) as cnt FROM messages WHERE fromMe = 1 GROUP BY sent_via;

-- Validation 2: Check for any remaining regressed statuses (fromMe with pending/error)
SELECT status, COUNT(*) as cnt FROM messages WHERE fromMe = 1 AND status IN ('pending', 'error') GROUP BY status;

-- Validation 3: Check wa_conversations preview status distribution for fromMe
SELECT lastStatus, COUNT(*) as cnt FROM wa_conversations WHERE lastFromMe = 1 GROUP BY lastStatus;

